FROM jsonb_to_recordset('[{"id": "cap-106-society-001", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "目前因婚姻關係來臺灣的新移民已超過50萬人，政府透過許多方式協助他們\n適應臺灣社會，例如建置數位資訊平臺，以多國語文的網頁介面，提供數位\n學習及文化交流的空間。上述多國語文最可能涵括下列何者？", "options": ["俄羅斯文、德文", "越南文、印尼文", "阿拉伯文、土耳其文", "西班牙文、葡萄牙文"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 1, "raw_text": "1.   目前因婚姻關係來臺灣的新移民已超過50萬人，政府透過許多方式協助他們\n     適應臺灣社會，例如建置數位資訊平臺，以多國語文的網頁介面，提供數位\n     學習及文化交流的空間。上述多國語文最可能涵括下列何者？\n     (A)俄羅斯文、德文\n     (B)越南文、印尼文\n     (C)阿拉伯文、土耳其文\n     (D)西班牙文、葡萄牙文\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-002", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "圖(一)為臺灣某次馬拉松比賽路線圖，參賽者在路跑過\n程中，最可能看到下列何種景觀？", "options": ["岬角與海灣相間", "潟湖、沙洲遍布", "大規模的隆起珊瑚礁 (D)陡直的峭壁、深切的峽谷                圖(一)", ""], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 2, "raw_text": "2.   圖(一)為臺灣某次馬拉松比賽路線圖，參賽者在路跑過\n     程中，最可能看到下列何種景觀？\n     (A)岬角與海灣相間\n     (B)潟湖、沙洲遍布\n     (C)大規模的隆起珊瑚礁\n     (D)陡直的峭壁、深切的峽谷                圖(一)"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-003", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "2014年，中國與甲國簽署了乳製品的合作協議，由於甲國向來以酪農業發達\n著稱，兩國合作將有助於提高中國乳製品的品質與產量。甲國最可能為下列\n何者？", "options": ["北韓", "荷蘭", "泰國", "挪威"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 3, "raw_text": "3.   2014年，中國與甲國簽署了乳製品的合作協議，由於甲國向來以酪農業發達\n     著稱，兩國合作將有助於提高中國乳製品的品質與產量。甲國最可能為下列\n     何者？\n     (A)北韓\n     (B)荷蘭\n     (C)泰國\n     (D)挪威\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-004", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "圖(二)為臺灣某月分的月平均等雨量線圖，根據圖中雨量\n的分布狀況判斷，該月分臺灣的氣候特色為下列何者？", "options": ["高溫多對流雨", "易形成滯留鋒", "東北季風盛行", "易受颱風侵襲 圖(二)"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 4, "raw_text": "4.   圖(二)為臺灣某月分的月平均等雨量線圖，根據圖中雨量\n     的分布狀況判斷，該月分臺灣的氣候特色為下列何者？\n     (A)高溫多對流雨\n     (B)易形成滯留鋒\n     (C)東北季風盛行\n     (D)易受颱風侵襲\n                                    圖(二)"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-005", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "某國的國旗以白色為底，上有藍色十字，充分展現該國的自然與人文特色。\n因該國有四分之一的國土在北極圈內，氣候寒冷，故白色象徵冬季白雪覆蓋\n的國土；藍色象徵境內廣布的冰蝕湖、河流；十字表示該國在歷史上與其他\n北歐鄰國的密切關係。上文是在介紹何國的國旗？", "options": ["丹麥", "芬蘭", "瑞士", "俄羅斯"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 5, "raw_text": "5.   某國的國旗以白色為底，上有藍色十字，充分展現該國的自然與人文特色。\n     因該國有四分之一的國土在北極圈內，氣候寒冷，故白色象徵冬季白雪覆蓋\n     的國土；藍色象徵境內廣布的冰蝕湖、河流；十字表示該國在歷史上與其他\n     北歐鄰國的密切關係。上文是在介紹何國的國旗？\n     (A)丹麥\n     (B)芬蘭\n     (C)瑞士\n     (D)俄羅斯\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-006", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "下列為臺灣某份刊物上刊載的文章：\n今日針對普及衛生思想，監督指導的單位須以身作則，首先應喚起市街庄行\n政人員的自覺，有效配合地方上保甲的力量。此外，藉由小學校、公學校對\n衛生教育的提倡、社會上報章雜誌的宣傳，來提升民眾的衛生意識。\n根據內容判斷，此段文章主要在討論下列何者？", "options": ["荷蘭聯合東印度公司推動衛生教育", "中華民國政府規畫與施行衛生教育", "清朝開港通商時，傳教士引進公共衛生觀念", "日本統治時期，政府與民間推廣公共衛生觀念"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 6, "raw_text": "6.   下列為臺灣某份刊物上刊載的文章：\n     今日針對普及衛生思想，監督指導的單位須以身作則，首先應喚起市街庄行\n     政人員的自覺，有效配合地方上保甲的力量。此外，藉由小學校、公學校對\n     衛生教育的提倡、社會上報章雜誌的宣傳，來提升民眾的衛生意識。\n     根據內容判斷，此段文章主要在討論下列何者？\n     (A)荷蘭聯合東印度公司推動衛生教育\n     (B)中華民國政府規畫與施行衛生教育\n     (C)清朝開港通商時，傳教士引進公共衛生觀念\n     (D)日本統治時期，政府與民間推廣公共衛生觀念\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-007", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "圖(三)是某機構的性質及工作內容示意圖。\n據此判斷，該機構最可能為下列何者？", "options": ["郊 & 郊＝行郊", "公行", "市舶司", "總理各國事務衙門 圖(三)"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 7, "raw_text": "7.   圖(三)是某機構的性質及工作內容示意圖。\n     據此判斷，該機構最可能為下列何者？\n     (A)郊\n                   & 郊＝行郊\n     (B)公行\n     (C)市舶司\n     (D)總理各國事務衙門\n                                      圖(三)\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-008", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "表(一)為清朝後期幾位地方總              表(一)\n督、巡撫的出身資料，根據內    姓名    民族   經歷       曾任職務\n容判斷，他們得以出任總督、巡   左宗棠               1861 年浙江巡撫\n撫，與下列何者關係最密切？    楊岳斌        皆為     1864 年陜甘總督\n皆為", "options": ["鴉片戰爭                     湘軍 劉坤一   漢人 將領     1865 年江西巡撫", "英 法聯軍 曾國荃               1865 年山西巡撫", "太平天國", "甲午戰爭"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 8, "raw_text": "8.   表(一)為清朝後期幾位地方總              表(一)\n     督、巡撫的出身資料，根據內    姓名    民族   經歷       曾任職務\n     容判斷，他們得以出任總督、巡   左宗棠               1861 年浙江巡撫\n     撫，與下列何者關係最密切？    楊岳斌        皆為     1864 年陜甘總督\n                            皆為\n     (A)鴉片戰爭                     湘軍\n                      劉坤一   漢人\n                                 將領     1865 年江西巡撫\n     (B)英 法聯軍\n                      曾國荃               1865 年山西巡撫\n     (C)太平天國\n     (D)甲午戰爭\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-009", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "以下是中國某朝代首都的簡介：「這是一座依計畫興建的城市，城中可見基\n督教教堂、伊斯蘭教清真寺及佛教寺廟。朝廷聘用色目人擔任財政官員，並\n推行全國性紙幣政策，加上各地物資的集中，讓這座城市成為金融經濟中\n心。」上述城市最可能是指下列何者？", "options": ["東漢 洛陽", "唐代 長安", "北宋 汴京", "元代 大都"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 9, "raw_text": "9.   以下是中國某朝代首都的簡介：「這是一座依計畫興建的城市，城中可見基\n     督教教堂、伊斯蘭教清真寺及佛教寺廟。朝廷聘用色目人擔任財政官員，並\n     推行全國性紙幣政策，加上各地物資的集中，讓這座城市成為金融經濟中\n     心。」上述城市最可能是指下列何者？\n     (A)東漢 洛陽      (B)唐代 長安\n     (C)北宋 汴京      (D)元代 大都\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-010", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "圖(四)是某一文件的部分內容，此文件最可能是下列何者？", "options": ["日本給劉永福的勸降書", "法軍將領給清廷的戰帖", "日本給牡丹社原住民的公告", "臺灣民主國給日本總督的通牒 圖(四)"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 10, "raw_text": "10. 圖(四)是某一文件的部分內容，此文件最可能是下列何者？\n    (A)日本給劉永福的勸降書\n    (B)法軍將領給清廷的戰帖\n    (C)日本給牡丹社原住民的公告\n    (D)臺灣民主國給日本總督的通牒\n\n                                             圖(四)\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-011", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "新聞報導：國外某一所大學在校園中舉辦臺灣文化節，多名來自臺灣的交換\n學生，熱情地介紹臺灣的特色美食與民情風俗，展現出臺灣多元文化的面\n貌，讓校內來自各國的學生驚豔不已……。根據上述報導內容判斷，下列何\n者最可能是校內舉辦此類活動的目的？", "options": ["擴展官方外交關係", "促進各國文化交流", "調適強勢文化衝擊", "推動多元文化融合"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 11, "raw_text": "11. 新聞報導：國外某一所大學在校園中舉辦臺灣文化節，多名來自臺灣的交換\n    學生，熱情地介紹臺灣的特色美食與民情風俗，展現出臺灣多元文化的面\n    貌，讓校內來自各國的學生驚豔不已……。根據上述報導內容判斷，下列何\n    者最可能是校內舉辦此類活動的目的？\n    (A)擴展官方外交關係\n    (B)促進各國文化交流\n    (C)調適強勢文化衝擊\n    (D)推動多元文化融合\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-012", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "13歲的小婷因羨慕朋友擁有最新型的手機，於是趁體育課偷走同學留在書包\n中的零用錢，行竊時被返回班上的同學撞見，受害學生家長獲知後決定報警\n處理。根據上述內容判斷，小婷最可能會受到下列何種處分？", "options": ["罰鍰一千元", "拘役二十五日", "罰金一千五百元", "假日生活輔導四次"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 12, "raw_text": "12. 13歲的小婷因羨慕朋友